{
  "title": "Exploring the Daydaye Cyber Area: Vlogging and Cybersecurity Basics",
  "description": "This course provides an introduction to the Daydaye Cyber Area in Myanmar, focusing on vlogging as a medium for sharing information while incorporating essential cybersecurity concepts for beginners.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to the Daydaye Cyber Area",
      "description": "An overview of the Daydaye Cyber Area, its significance in Myanmar, and the role of digital content creation in this context."
    },
    {
      "id": "module2",
      "title": "Understanding Vlogs and Their Impact",
      "description": "Exploration of vlogs as a popular form of digital content, including techniques for creating engaging vlogs and their influence on audiences."
    },
    {
      "id": "module3",
      "title": "Basic Cybersecurity Concepts for Vloggers",
      "description": "Introduction to fundamental cybersecurity principles, focusing on how vloggers can protect their content and personal information online."
    },
    {
      "id": "module4",
      "title": "Creating Safe and Engaging Vlogs",
      "description": "Practical guidance on producing vlogs that are both captivating and secure, including tips on content planning, filming, and post-production with a cybersecurity mindset."
    }
  ]
}
